  if (!promise || typeof promise.then !== 'function') {
    throw new TypeError('First argument must be a Promise');
  }
  if (typeof ms !== 'number' || ms < 0 || !isFinite(ms)) {
    throw new TypeError('Timeout must be a positive finite number');
  }

  const { signal, timeoutMessage } = options;

  // Check if already aborted
  if (signal?.aborted) {
    throw new Error('Operation was aborted');
  }

  let timeoutId;
  let cleanup = () => {};

  const timeoutPromise = new Promise((_, reject) => {
    timeoutId = setTimeout(() => {
      reject(new Error(timeoutMessage || `Operation timed out after ${ms}ms`));
